var e=JSON.parse(`[{"id":"L9_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"저건......?","JPN":"あれは……？","ENG":"What's that?","TWN":"那是……？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"차원 폭풍이군요. 자연적으로 발생하는 건 드문 일인데......","JPN":"次元の暴風ですね。自然発生は稀ですが……","ENG":"A dimensional storm. It rarely occurs naturally.","TWN":"是次元風暴呢。會自然發生還真是稀奇……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"더 가까이 접근하면 위험할 수도 있습니다.","JPN":"これ以上近づくのは危険です。","ENG":"We shouldn't get closer. It's too dangerous.","TWN":"但我們繼續靠近的話，可能會發生危險。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L12_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"이상하군.","JPN":"妙だな。","ENG":"This is strange.","TWN":"奇怪。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"차원 폭풍이 발생하는 곳은 일반적으로 고순도 이터니움 광맥이 있는 곳이지.","JPN":"次元の暴風は、一般的に高純度エタニウムの鉱脈がある場所に発生する。","ENG":"Dimensional storms usually occur around high-purity Eternium veins.","TWN":"會發生次元風暴的地方，一般都會有高純度永恆之金的礦脈吧。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L14_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"채굴 업체들이라면 모를까, 전술 평가작전을 진행하기에 적절한 장소는 아니야.","JPN":"採掘業者ならともかく、戦術評価作戦の遂行にふさわしい場所ではない。","ENG":"This may be a popular spot among mining companies, but it's not a good place to carry out tactical evaluations.","TWN":"是開採業者就算了，但這裡並不適合進行戰術評估作戰啊。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"어째서 우리를 이런 곳으로 부른 거지?","JPN":"どうして我々をこんな場所に呼んだんだ？","ENG":"Why did they call us here?","TWN":"怎麼會把我們叫到這種地方來？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"메이데이! 메이데이!","JPN":"メーデー！　メーデー！","ENG":"Mayday! Mayday!","TWN":"緊急求救！緊急求救！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"여기는 정보부 파견대 지휘관, 블랙 버드!","JPN":"こちら情報局支隊指揮官のブラックバード！","ENG":"This is Commander Blackbird, of the Intelligence Agency detached force!","TWN":"這裡是情報部派遣隊指揮官，黑鳥！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"현재 차원 폭풍으로부터 나타난 대규모 침식체 무리로부터 공격 받고 있다!","JPN":"現在、次元の暴風から現れた侵食体の大群に攻撃されている！","ENG":"We're under attack by a large horde of C.O.s that came out of a dimensional storm!","TWN":"我們現在正遭受從次元風暴中出現的大規模侵蝕體群的攻擊！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"즉시 구원을 요청한다!","JPN":"ただちに救援を要請する！","ENG":"We need help right away!","TWN":"請求立即救援！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"용병이든 뭐든 좋아! 이 통신을 듣는 자는 누구라도 좋으니까 당장 도와달라고!","JPN":"傭兵だろうが何だろうが関係ない！\\nこの連絡を聞いたなら、誰でもいいから今すぐ助けてほしい！","ENG":"I don't care if you're mercenaries. If you can hear me, please come help us!","TWN":"傭兵也好，什麼都行！無論是誰聽到這則通信，請馬上來幫我們！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JACOB_NPC_NULL_NULL","text":{"KOREA":"제기랄, 차원 폭풍이 이렇게 심한데 통신 연결이 되겠어?!","JPN":"くそっ、次元の暴風がこんなに吹き荒れている状態で\\n通信なんて繋がるのかよ！？","ENG":"Drat, this dimensional storm is too strong! There's no way anyone can hear us!","TWN":"該死的，次元風暴這麼嚴重，通信還連接的上嗎？！"},"stage":{"bg":"WAREHOUSE_01","slots":{"L":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L26_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"그럼 그냥 앉아서 죽을 생각인가?!","JPN":"なら、このまま座して死を待つのか！？","ENG":"But we can't just sit here and wait to die!","TWN":"不然怎麼辦，坐著等死嗎？！"},"stage":{"bg":"WAREHOUSE_01","slots":{"L":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L27_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"우린 전투부대가 아니라 정보부대라고!","JPN":"俺らは戦闘部隊ではなく情報部隊なんだ！","ENG":"We're not combatants—we're intelligence agents!","TWN":"我們不是戰鬥部隊，是情報部隊啊！"},"stage":{"bg":"WAREHOUSE_01","slots":{"L":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_HATE"}}}}]`);export{e as default};